const p = $input.first().json.body || $input.first().json;
const envioId = p.envio_id || "";
const clienteNombre = p.cliente_nombre || "Cliente";
const clienteTelefono = p.cliente_telefono || "";
const estadoNuevo = p.estado_nuevo || "";
const eta = p.eta || "";
const nota = p.nota || "";

const system_prompt = "Eres el asistente de atencion al cliente de una empresa de logistica y transporte de carga (import-export). Redactas actualizaciones de estado de envio para el cliente.

Datos del envio:
- envio_id: " + envioId + "
- cliente: " + clienteNombre + "
- estado_nuevo: " + estadoNuevo + " (valores posibles: en_aduana, en_transito, retrasado, entregado)
- eta estimada: " + eta + "
- nota interna: " + nota + "

Tarea: redacta un mensaje de WhatsApp claro y tranquilizador para el cliente sobre el nuevo estado de su envio, y decide si esta actualizacion necesita alertar tambien al gerente de cuenta.

Reglas:
- prioridad ALTA: el estado es retrasado, o hay un problema aduanal, o el ETA se movio significativamente.
- prioridad NORMAL: avance esperado del envio (en_transito, en_aduana sin problema, entregado).

Responde UNICAMENTE con un JSON valido, sin texto extra:
- prioridad: ALTA o NORMAL
- mensaje_cliente: mensaje corto en espanol, claro y tranquilizador, explicando el estado y el proximo paso. Maximo 3 frases.
- razon_gerente: si prioridad es ALTA, explica en 1 frase por que el gerente de cuenta debe intervenir; si es NORMAL, deja este campo vacio.";

return [{ json: Object.assign({}, p, { system_prompt: system_prompt, envio_id: envioId, cliente_nombre: clienteNombre, cliente_telefono: clienteTelefono }) }];

const original = $("Armar Prompt de Actualizacion").first().json;
const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, "").replace(/```\s*$/, "");
const contenido = JSON.parse(limpio);
return [{ json: Object.assign({}, contenido, { envio_id: original.envio_id, cliente_nombre: original.cliente_nombre, cliente_telefono: original.cliente_telefono }) }];
